var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"후우.","JPN":"ふぅ。","ENG":"Whew.","TWN":"呼。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"해, 해치웠나?","JPN":"や、やっつけた？","ENG":"D-did we get them?","TWN":"你，都處理掉啦？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저게 침식체라는 사실을 알고 있었나? 역시 평범한 사람은 아니었군.","JPN":"あれが侵食体だとわかるとは、やはり一般人ではなかったか。","ENG":"You knew that those things were C.O.s? So you aren't an ordinary person.","TWN":"你知道那些是侵蝕體嗎？你果然不是普通人。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"蛤？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체는 사람들에게 알려져선 안 되는 존재야. 그런 존재를 단번에 알아보다니.","JPN":"侵食体の存在は、一般市民には知らせていない極秘情報のはずだ。それを一発で見分けるとは。","ENG":"C.O.s are entities that shouldn't be known to the public. But you are able to recognize them right away,","TWN":"侵蝕體是不為大眾所知的存在，而你竟然可以一眼就認出它們。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"역시 평범한 척 사실은 비밀 작전을 수행하는…….","JPN":"やはり平凡を装った、機密作戦の実行者……","ENG":"I knew it… I knew you were actually performing a secret operation.","TWN":"你只是偽裝成普通人，實際上在執行秘密作戰……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그게 대체 무슨 말씀이세요?","JPN":"いったい何をおっしゃっているんですか？","ENG":"What are you talking about?","TWN":"你到底在說什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"침식체의 존재는 대정화 전쟁 이전부터 조금씩 관측되어 왔다고 해요.","JPN":"侵食体は大浄化戦争より以前から、その存在が観測されてきたそうです。","ENG":"The existence of C.O.s is said to have been gradually observed since before the Grand Purification War.","TWN":"我聽說侵蝕體的存在，是從淨化之戰之前就有稍微觀測到。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이건 조금만 역사에 관심이 있으면 알 수 있는 이야기죠.","JPN":"これは、歴史に少しでも興味がある人なら、誰もが知っている話です。","ENG":"Anyone who has even the slightest interest in history would know this.","TWN":"只要對歷史稍微有點興趣就可以知道吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 아까 뭘 들으신 거예요? 대정화 전쟁과 태스크포스 출범은 침식체와 떼어놓을 수 없는 관계란 말이에요!","JPN":"それに、さっきも言ったはずです！　大浄化戦争とタスクフォースの始まりは、侵食体と密接な関係性があるんです！","ENG":"And weren't you paying attention earlier? The Grand Purification War and the emergence of TASKFORCEs are inseparable from C.O.s!","TWN":"而且你剛有注意聽嗎？我不是說淨化之戰和特遣勢力的出現與侵蝕體是密不可分的關係。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"북극점 작전이라던가, 태스크포스 1 델타 세븐의 출범이라던가……. 오, 로터스하면 또 천년의 역사를 지닌 도시, 에리두를 빼먹을 수 없죠. 에리두는 20년 전만 해도 다른 이름으로 불렸었는데요…….","JPN":"北極点作戦、タスクフォース1デルタセブンの登場……ああ、ロータスといえば千年の歴史を持つ都市、エリドゥ抜きでは語れません。エリドゥは20年前までは別の名称で呼ばれていたらしいですが……","ENG":"The Operation North Pole, the launch of TASKFORCE No. 1 Delta Seven... Oh! Speaking of Lotus, you can't leave out the city with a thousand-year history, Eridu, too. Eridu was referred to by a different name twenty years ago...","TWN":"是叫北極點行動嗎？特遣勢力1第七三角洲橫空出世……喔！說到洛德斯也有千年以上的歷史，不能不提到埃里都。埃里都在20年前並不是這個名字……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……그만하면 됐다.","JPN":"……もう十分だ。","ENG":"...That’s enough.","TWN":"……可以了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님이 잠들어 계신 동안 많은 일이 일어났다고요!","JPN":"アーディティヤ様が眠っている間、たくさんのことがあったんです！","ENG":"A lot has happened while you were asleep, Miss Aditya!","TWN":"阿迪亞，在你沉睡的這段期間世界改變很多！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아무튼! 아무것도 모르는 분에게 특별히 알려드리는 상식이에요. 상식!","JPN":"とにかく！　何もわかっていないあなたに一般常識を教えているだけなんですから！","ENG":"Anyway! This is common knowledge that I'm generously explaining to someone who knows nothing! Common knowledge!","TWN":"總之！這些都是常識，是因為你什麼都不知道，我才特地跟你說的！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"잠깐 눈을 감았다가 떴는데 20년이 넘게 지나가 있으면, 누구라도 이런 반응이지 않겠나?","JPN":"眠りから覚めて20年も過ぎていたら、誰もが私のような反応をすると思わないか？","ENG":"Wouldn't anyone react the way I did if they suddenly woke up and twenty years had gone by?","TWN":"我只是稍微閉個眼，再睜開眼睛已經是20年後，任誰都會有這種反應吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"죄, 죄송해요. 놀리려는 의도는 아니었어요.","JPN":"す、すみません。怒らせるつもりじゃなかったんです……","ENG":"I-I'm sorry. I wasn't trying to make fun of you.","TWN":"對，對不起，我沒有要嘲笑你的意思。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"잠깐, 그럼 옛날에도 인간을 동결시키는 기술이 존재했었단 말이에요?","JPN":"でも、ということは、そんな大昔にも人間を凍結させる技術があったということですか？","ENG":"Hold on. Then, even back in the old days, the technology existed to put people into cryogenic sleep?","TWN":"等等，你的意思是，古代就有這種把人冰封起來的技術嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"옛날…….","JPN":"大昔……","ENG":"Old days...","TWN":"古代……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"혹시 비밀 기업의 실험체? 아니면 매드 사이언티스트? 악당 세력의 비밀 병기?","JPN":"もしかして秘密機関の実験体？　それともマッドサイエンティスト？　悪の組織の秘密兵器とか？","ENG":"Were you a test subject for a secret company? Or maybe even a mad scientist? Ooh! What about a villain's secret weapon?","TWN":"難道你是神秘企業的實驗品？還是瘋狂科學家？或是邪惡勢力的秘密武器？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아직 내가 모르는 비밀스러운 역사가 존재했다니!","JPN":"私が知らない秘史がまだあったなんて！","ENG":"I can't believe there was a part of history that I knew nothing about!","TWN":"竟然還有我不知道的歷史秘密！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"프리메이슨? 일루미나티? 오! 렙틸리언이 실제로 존재하는 건가요?!","JPN":"フリーメーソン？　イルミナティ？　おおっ、ヒト型爬虫類は実在するんですか！？","ENG":"Freemasonry? Illuminati? Oh! Do reptilians really exist?!","TWN":"共濟會？光明會？還是！蜥蜴人是真實存在的嗎？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"흠흠. 아닌가 보네요. 아무튼! 침식체를 무사히 해치워서 다행이에요.","JPN":"ふむ、流石に行き過ぎですかね。まぁ、とにかく！　侵食体を倒すことができて助かりました。","ENG":"Ahem. I guess not. Anyway! I'm glad you got rid of the C.O.s.","TWN":"嗯，看來不是。總之！你對付侵蝕體的時候沒受傷就好。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하…… 본론으로 들어가도록 하지. 아버지를 알던 사람이 아무도 없었나?","JPN":"ふう……本題に入ろう。お父さんのことを知っている人物に会ったことはないか？","ENG":"*Sigh* ...Let's get back on topic. Is there anyone who knew your father?","TWN":"哀……我們回到正題吧。都沒有人認識你爸爸嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어머니, 주변 인물, 친인척, 하다못해 서류상의 기록이라도 말이야.","JPN":"お母さんや周辺人物、親族、なにか記録に残っている関係者でも構わない。","ENG":"Your mother, neighbors, relatives, or even a record in some document.","TWN":"你媽媽、周圍親朋好友，再不然文件上的紀錄也可以，這些都沒有嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어머니가 침식 재난으로 돌아가시고 나서 살아남기 위해 이곳저곳 떠돌아다녔어요.","JPN":"お母さんが侵食災害によって亡くなってから、生き延びるためにあちこち渡り歩いていました。","ENG":"After my mother passed away from the Corruption Disaster, I've been wandering around to survive.","TWN":"媽媽在侵蝕災難中過世後，我便四處流浪。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그로니아부터 시작해서 안 가본 곳이 없을 정도로요.","JPN":"グロニアをはじめ、行ったことのない場所はありません。","ENG":"Starting from Gronia, there is not a place that I haven't been to.","TWN":"從格羅尼亞為起點，我幾乎是走遍所有地方。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 과정에서 어머니를 아는 사람은 봤어도, 아버지를 아는 사람을 만난 적은 없었어요.","JPN":"でも、その中で、お母さんを知っている人に会ったことはあっても、お父さんについて知っている人に会ったことはありません。","ENG":"In the process, I've met a few people who knew my mother, but not a single one knew who my father was.","TWN":"在這過程中，雖然有遇到認識媽媽的人，但卻沒有一個人是認識爸爸的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제 출생 기록을 본 적도 있지만 서류에도 아버지의 흔적은 없었죠.","JPN":"自分の出生届も確認してみましたが、書類にすらお父さんの名前はありませんでした。","ENG":"I've seen my birth certificate, but there were no traces of him even there.","TWN":"我也看過的出生證明，上面也是父不詳。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 분명…… 아버지가 남긴 것들은 있다고 생각하거든요. 참 이상해요.","JPN":"でも……なぜかお父さんが残したものは、確かにあるって思えるんです。不思議ですね。","ENG":"But I'm certain... that there must be something my father left me. So odd, isn't it?","TWN":"但……爸爸明明就有留下某些東西，這真的很詭異。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님을 가리키던 나침반, 집에서 발견한 앨범 속에 꽂힌 빈 인화지 같은 것들이요.","JPN":"アーディティヤ様を指し示していた羅針盤や、家で見つけたアルバムに挟んであった空っぽの印画紙とかです。","ENG":"For instance, the compass that was pointing to you, and an empty photo paper that I found inside an album back home.","TWN":"像是指著你的指南針，還有在家中發現的相簿中夾著的空白感應紙。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이건 분명 아버지가 존재했다는 흔적이에요. 하지만 이를 증명할 수단이 모두 사라졌어요.","JPN":"確かにそこにいたんです、お父さんが……でも、それを証明する手段がもうどこにも残っていません。","ENG":"These are definitely signs that he existed, but I've lost all means to prove it.","TWN":"這些很明顯都是爸爸存在過的痕跡，只是沒有方法可以證明這一點。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"누군가 아버지의 존재를 저에게 알려주고 싶지 않은 것처럼 말이에요.","JPN":"まるで、私をお父さんの存在に近づけまいとする意思が働いているみたいに。","ENG":"It's as if someone doesn't want me to know who he is.","TWN":"彷彿是有人不希望我知道爸爸的存在一樣。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};